// ============================================================
// src/App.js — Top-level screen router
// ============================================================
import React, { useState, useCallback } from "react";
import Lobby        from "./components/Lobby";
import GameScreen   from "./components/GameScreen";
import VoteScreen   from "./components/VoteScreen";
import ResultScreen from "./components/ResultScreen";
import "./App.css";

// App-level screens: lobby | game | vote | result
export default function App() {
  const [screen, setScreen]   = useState("lobby");
  const [game, setGame]       = useState(null);
  const [player, setPlayer]   = useState(null);
  const [voteData, setVoteData] = useState(null);
  const [result, setResult]   = useState(null);

  // Lobby → Game
  const handleGameStart = useCallback((g, p) => {
    setGame(g);
    setPlayer(p);
    setScreen("game");
  }, []);

  // Game → Vote
  const handleVoting = useCallback((data) => {
    setVoteData(data);
    setScreen("vote");
  }, []);

  // Vote/Game → Result
  const handleResult = useCallback((data) => {
    setResult(data);
    setScreen("result");
  }, []);

  // Result → Game (next round)
  const handleNextRound = useCallback(() => {
    setScreen("game");
  }, []);

  // Result → Lobby (play again)
  const handleGameOver = useCallback(() => {
    setGame(null);
    setPlayer(null);
    setVoteData(null);
    setResult(null);
    setScreen("lobby");
  }, []);

  return (
    <div className="app-root">
      {screen === "lobby"  && <Lobby onGameStart={handleGameStart} />}
      {screen === "game"   && <GameScreen game={game} player={player} onVoting={handleVoting} onResult={handleResult} />}
      {screen === "vote"   && <VoteScreen game={game} player={player} voteData={voteData} onResult={handleResult} />}
      {screen === "result" && <ResultScreen game={game} player={player} result={result} onNextRound={handleNextRound} onGameOver={handleGameOver} />}
    </div>
  );
}
